package com.fasterxml.jackson.databind;

import org.junit.runner.RunWith;
import cucumber.api.junit.Cucumber;

@RunWith(Cucumber.class)
public class CucumberTest {
}

package com.fasterxml.jackson.databind.steps;

import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.exc.MismatchedInputException;
import cucumber.api.java.en.Given;
import cucumber.api.java.en.When;
import cucumber.api.java.en.Then;
import org.junit.Assert;

import java.util.Map;

public class StepDefs {
    private String jsonInput;
    private ObjectMapper objectMapper;
    private Exception exception;
    private Map<TestEnum, Integer> targetType;

    public enum TestEnum {
        // Empty enum to force the deserialization error
    }

    @Given("^a JSON input \"(.*)\"$")
    public void a_JSON_input(String input) {
        this.jsonInput = input;
    }

    @Given("^a target type Map<Enum, Integer> where the Enum key does not contain \"(.*)\"$")
    public void a_target_type_Map_Enum_Integer(String key) {
        this.objectMapper = new ObjectMapper();
    }

    @When("^the JSON is deserialized$")
    public void the_JSON_is_deserialized() {
        try {
            // This should throw an exception since TestEnum doesn't contain the required key
            targetType = objectMapper.readValue(jsonInput, new TypeReference<Map<TestEnum, Integer>>() {});
        } catch (Exception e) {
            this.exception = e;
        }
    }

    @Then("^a MismatchedInputException should be thrown$")
    public void a_MismatchedInputException_should_be_thrown() {
        Assert.assertNotNull("Exception should have been thrown", exception);
        Assert.assertTrue("Exception should be MismatchedInputException", 
                         exception instanceof MismatchedInputException);
    }

    @Then("^the exception message should contain the text \"(.*)\" exactly once$")
    public void the_exception_message_should_contain_the_text_exactly_once(String text) {
        Assert.assertNotNull("Exception should have been thrown", exception);
        String message = exception.getMessage();
        Assert.assertNotNull("Exception message should not be null", message);

        // Count occurrences of the text
        int count = 0;
        int index = 0;
        while ((index = message.indexOf(text, index)) != -1) {
            count++;
            index += text.length();
        }

        Assert.assertEquals("Text '" + text + "' should appear exactly once in the exception message", 1, count);
    }
}
